-- history-tea character catalog (auto-generated)
-- Idempotent: removes existing history-tea chars, then re-inserts.

DELETE FROM character_stories WHERE character_id IN (SELECT id FROM characters WHERE app_id = 'history-tea');
DELETE FROM characters WHERE app_id = 'history-tea';

INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-hammurabi', 'Hammurabi', 'The king who wrote the law. King of Babylon around 1750 BCE. He carved 282 laws onto a stone pillar and declared them for everyone — kings, priests, and commoners alike. The first legal code of civilization, and the ancestor of every law book you''ve ever heard of.', 'characters/hammurabi.webp', 0, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-hammurabi', 'st-hammurabi');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-cyrus-the-great', 'Cyrus the Great', 'Builder of the first world empire. Founder of the Persian Empire, the largest empire the world had ever seen. Famous for tolerance — he freed captive peoples, respected local religions, and wrote a declaration of human rights two thousand years before anyone else.', 'characters/cyrus-the-great.webp', 1, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-cyrus-the-great', 'st-cyrus-the-great');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-cyrus-the-great', 'st-fall-of-babylon');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-ramses-ii', 'Ramses II', 'Pharaoh of Pharaohs. The greatest builder Egypt ever saw. Ruled for 66 years, fathered 100+ children, built temples from Abu Simbel to Memphis, and fought one of history''s first recorded battles at Kadesh. Then signed the first known peace treaty.', 'characters/ramses-ii.webp', 2, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-ramses-ii', 'st-ramses-ii');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-ramses-ii', 'st-battle-of-kadesh');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-cleopatra', 'Cleopatra', 'The last Pharaoh. Brilliant, multilingual, politically ruthless. She seduced Caesar, partnered with Antony, and fought Rome itself to save her kingdom. When she lost, she chose death by asp over surrender. The end of Ancient Egypt.', 'characters/cleopatra.webp', 3, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-cleopatra', 'st-cleopatra-caesar');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-cleopatra', 'st-cleopatra-and-antony');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-cleopatra', 'st-battle-of-actium');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-cleopatra', 'st-death-of-cleopatra');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-alexander-the-great', 'Alexander the Great', 'Conqueror of the known world. Tutored by Aristotle, king at 20, world conqueror by 30. He marched from Greece to India, never lost a battle, and reshaped civilization. Then died mysteriously at 32 with no heir — and his empire shattered.', 'characters/alexander-the-great.webp', 4, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-alexander-the-great', 'st-alexander');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-alexander-the-great', 'st-alexander-cuts-the-knot');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-alexander-the-great', 'st-death-of-alexander');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-leonidas', 'Leonidas', 'The Spartan king at Thermopylae. King of Sparta. Stood at the Hot Gates with 300 Spartans and a few thousand allies against the Persian army. Held them for three days. Died fighting — and became the most legendary last stand in history.', 'characters/leonidas.webp', 5, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-leonidas', 'st-thermopylae');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-socrates', 'Socrates', 'The father of philosophy. He asked questions nobody wanted to answer and annoyed Athens into a death sentence. Drank the hemlock and kept teaching until his last breath. His method still runs every philosophy class 2,400 years later.', 'characters/socrates.webp', 6, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-socrates', 'st-socrates');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-plato', 'Plato', 'Founder of the Academy. Socrates'' best student, Aristotle''s teacher. Wrote down the dialogues that preserved his teacher''s ideas, then built the first institution of higher learning — the Academy — that shaped Western thought forever.', 'characters/plato.webp', 7, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-plato', 'st-platos-academy');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-archimedes', 'Archimedes', 'Eureka!. Greatest scientist of antiquity. Discovered displacement in the bath, designed war machines that held off Rome for years, and got so absorbed in geometry he didn''t notice a Roman soldier was about to kill him.', 'characters/archimedes.webp', 8, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-archimedes', 'st-archimedes-eureka');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-julius-caesar', 'Julius Caesar', 'Veni, vidi, vici. Conquered Gaul, crossed the Rubicon, defeated Pompey, and became dictator of Rome. Then 23 senators stabbed him in broad daylight. His death ended the Republic — and his grand-nephew built an empire on it.', 'characters/julius-caesar.webp', 9, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-julius-caesar', 'st-caesar-conquers-gaul');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-julius-caesar', 'st-rubicon');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-julius-caesar', 'st-first-triumvirate');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-julius-caesar', 'st-ides-of-march');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-hannibal', 'Hannibal Barca', 'Rome''s greatest nightmare. Carthaginian general who swore as a child to destroy Rome. Then actually did the impossible — marched war elephants over the Alps, smashed Roman armies for 15 years, and came within miles of sacking the city.', 'characters/hannibal.webp', 10, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-hannibal', 'st-hannibal');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-hannibal', 'st-battle-of-cannae');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-augustus', 'Augustus', 'Rome''s first emperor. Caesar''s teenage grand-nephew became the shrewdest politician in history. Defeated Antony and Cleopatra, ended a century of civil war, and quietly turned the Republic into an empire that lasted 500 years.', 'characters/augustus.webp', 11, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-augustus', 'st-augustus-becomes-emperor');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-augustus', 'st-battle-of-actium');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-marcus-aurelius', 'Marcus Aurelius', 'The philosopher emperor. Roman emperor who ruled at the height of the empire and wrote personal journals about virtue while on military campaigns. His Meditations are still read today. The last of the ''Five Good Emperors.''', 'characters/marcus-aurelius.webp', 12, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-marcus-aurelius', 'st-marcus-aurelius-philosopher-king');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-constantine', 'Constantine the Great', 'The emperor who converted Rome. Saw a cross in the sky, won a civil war in its name, then made Christianity legal across the empire. Founded Constantinople and called the Council of Nicaea. Turned Rome from pagan to Christian forever.', 'characters/constantine.webp', 13, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-constantine', 'st-constantine-converts');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-constantine', 'st-council-of-nicaea');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-justinian', 'Justinian', 'The Byzantine reformer. Emperor of the Eastern Roman Empire. Rewrote Roman law into the Code that shaped every legal system after it, built the Hagia Sophia, and nearly reconquered the old Western empire. His wife Theodora ran the show with him.', 'characters/justinian.webp', 14, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-justinian', 'st-justinian-and-theodora');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-justinian', 'st-hagia-sophia-rises');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-justinian', 'st-justinian-plague');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-justinian', 'st-the-nika-riots');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-charlemagne', 'Charlemagne', 'Father of Europe. Frankish king crowned Holy Roman Emperor on Christmas Day 800. Ruled most of Western Europe, revived learning after centuries of decay, and became the template for every medieval monarch who followed.', 'characters/charlemagne.webp', 15, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-charlemagne', 'st-charlemagne-crowned');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-william-the-conqueror', 'William the Conqueror', 'The Norman who took England. Duke of Normandy who crossed the Channel in 1066, killed King Harold at Hastings, and became King of England. His invasion rewired English government, language, and culture for a thousand years.', 'characters/william-the-conqueror.webp', 16, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-william-the-conqueror', 'st-battle-of-hastings');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-saladin', 'Saladin', 'The sultan who took Jerusalem. Kurdish-born founder of the Ayyubid dynasty. Drove the Crusaders out of Jerusalem in 1187 but did it with such famous mercy that even his European enemies admired him. The gold standard of chivalry.', 'characters/saladin.webp', 17, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-saladin', 'st-saladin-retakes-jerusalem');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-genghis-khan', 'Genghis Khan', 'The great khan. Born an outcast on the Mongolian steppe, he united the tribes and built the largest contiguous empire in human history. Merciless in war, brilliant at governance, and terrifyingly fast — he reshaped Eurasia forever.', 'characters/genghis-khan.webp', 18, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-genghis-khan', 'st-genghis-khan');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-marco-polo', 'Marco Polo', 'The Venetian in China. Venetian merchant who spent 17 years at Kublai Khan''s court and wrote the book that introduced Europe to Asia. Most of his contemporaries thought he was lying. Columbus sailed west with a copy in his hand.', 'characters/marco-polo.webp', 19, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-marco-polo', 'st-marco-polo-in-china');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-joan-of-arc', 'Joan of Arc', 'The Maid of Orléans. A teenage peasant girl who said God told her to save France, talked her way into commanding an army, and actually did it. Captured, tried, and burned at 19. Canonized a saint 500 years later.', 'characters/joan-of-arc.webp', 20, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-joan-of-arc', 'st-joan-of-arc');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-leonardo-da-vinci', 'Leonardo da Vinci', 'The Renaissance mind. Painter of the Mona Lisa, engineer of flying machines, anatomist, inventor, musician. The original polymath who saw the world as one giant puzzle to solve. Florence''s gift to humanity.', 'characters/leonardo-da-vinci.webp', 21, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-leonardo-da-vinci', 'st-da-vinci');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-michelangelo', 'Michelangelo', 'Sculptor of the divine. Carved the David, painted the Sistine Chapel ceiling flat on his back, and designed St. Peter''s dome. Fought with popes, outworked rivals, and lived to 88 still chipping away at stone.', 'characters/michelangelo.webp', 22, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-michelangelo', 'st-michelangelo-and-the-sistine');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-martin-luther', 'Martin Luther', 'The monk who split Christianity. German monk who nailed 95 complaints to a church door and accidentally started the Reformation. Translated the Bible into German, married an ex-nun, and broke the thousand-year grip of the medieval church.', 'characters/martin-luther.webp', 23, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-martin-luther', 'st-luther');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-henry-viii', 'Henry VIII', 'The king who married six times. Tudor king of England. Broke with Rome to get divorced, married six wives (two beheaded), and turned his court into a soap opera nobody could look away from. Left behind a new church and a queen — Elizabeth.', 'characters/henry-viii.webp', 24, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-henry-viii', 'st-henry-viii');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-henry-viii', 'st-anne-boleyn-beheaded');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-elizabeth-i', 'Elizabeth I', 'The Virgin Queen. Henry VIII''s daughter, imprisoned as a teenager, crowned at 25. Ruled England for 44 years, defeated the Spanish Armada, and presided over Shakespeare''s golden age — all without ever marrying.', 'characters/elizabeth-i.webp', 25, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-elizabeth-i', 'st-elizabeth-i');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-elizabeth-i', 'st-spanish-armada');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-columbus', 'Christopher Columbus', 'The accidental world-changer. Genoese sailor who convinced Spain to fund a westward voyage to Asia. He never reached Asia — he bumped into the Americas and spent the rest of his life insisting he hadn''t. The collision of worlds starts with him.', 'characters/columbus.webp', 26, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-columbus', 'st-columbus');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-magellan', 'Ferdinand Magellan', 'First to circle the world. Portuguese navigator who sailed for Spain and proved the Earth was round by accident. He died halfway through the voyage in the Philippines, but his crew limped home — the first humans to circumnavigate the globe.', 'characters/magellan.webp', 27, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-magellan', 'st-magellan-circumnavigates');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-galileo', 'Galileo Galilei', 'The father of modern science. Pointed his telescope at the sky, saw moons around Jupiter, and proved Earth wasn''t the center of everything. The Church put him on trial. He muttered ''and yet it moves'' — and modern science began.', 'characters/galileo.webp', 28, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-galileo', 'st-galileos-trial');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-louis-xiv', 'Louis XIV', 'The Sun King. Ruled France for 72 years — the longest reign of any European monarch. Built Versailles, turned the nobility into glorified courtiers, and made France the cultural capital of Europe. ''L''état, c''est moi.''', 'characters/louis-xiv.webp', 29, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-louis-xiv', 'st-louis-xiv-versailles');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-newton', 'Isaac Newton', 'The laws of the universe. Watched an apple fall and figured out gravity, motion, and calculus — most of it during a plague year locked in his mother''s house. Rewrote how humans understand the universe in one decade.', 'characters/newton.webp', 30, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-newton', 'st-newtons-apple');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-george-washington', 'George Washington', 'The first American president. Virginian planter who commanded the Continental Army, beat the British Empire, refused to become a king, and walked away after two terms. Set every precedent for American democracy by being the guy who didn''t grab power.', 'characters/george-washington.webp', 31, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-george-washington', 'st-washington-crosses-the-delaware');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-george-washington', 'st-yorktown-surrender');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-napoleon', 'Napoleon Bonaparte', 'Emperor of the French. Corsican artillery officer who rode the French Revolution all the way to emperor. Conquered most of Europe twice, rewrote its laws, and lost it all at Waterloo. Died exiled on a rock in the Atlantic.', 'characters/napoleon.webp', 32, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-napoleon', 'st-napoleon');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-napoleon', 'st-napoleon-crowns-himself');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-napoleon', 'st-battle-of-austerlitz');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-napoleon', 'st-napoleon-invades-russia');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-napoleon', 'st-waterloo');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-napoleon', 'st-napoleon-at-st-helena');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-marie-antoinette', 'Marie Antoinette', 'The last queen of France. Austrian teenager married off to the French king. Scapegoated for a broken system, accused of everything from treason to incest, and guillotined at 37. ''Let them eat cake'' — she never said it.', 'characters/marie-antoinette.webp', 33, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-marie-antoinette', 'st-marie-antoinette');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-darwin', 'Charles Darwin', 'The man who rewrote biology. Sailed on the Beagle to the Galápagos, noticed finches with different beaks, and came home with an idea so explosive he sat on it for 20 years. When he finally published, the whole picture of life on Earth changed.', 'characters/darwin.webp', 34, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-darwin', 'st-darwin-publishes-origin');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-abraham-lincoln', 'Abraham Lincoln', 'The Great Emancipator. Self-taught frontier lawyer who became America''s 16th president. Led the Union through the Civil War, ended slavery, and was shot five days after the Confederacy surrendered. Every modern democracy borrows his cadence.', 'characters/abraham-lincoln.webp', 35, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-abraham-lincoln', 'st-lincoln-elected');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-abraham-lincoln', 'st-emancipation-proclamation');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-abraham-lincoln', 'st-lincoln-assassinated');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-churchill', 'Winston Churchill', 'Britain in the storm. Aristocrat, war correspondent, painter, and drinker. Britain''s prime minister during World War II, he held the line against Hitler with speeches alone for an entire year until the Americans showed up. ''We shall never surrender.''', 'characters/churchill.webp', 36, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-churchill', 'st-battle-of-britain');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-churchill', 'st-invasion-of-poland');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-jfk', 'John F. Kennedy', 'The young American president. Second-youngest US president ever. Faced down the Soviets in the Cuban Missile Crisis, promised to put a man on the moon, and was assassinated in Dallas at 46. The Camelot myth never quite went away.', 'characters/jfk.webp', 37, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-jfk', 'st-cuban-missile-crisis');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-jfk', 'st-jfk-assassinated');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-mlk', 'Martin Luther King Jr.', 'I have a dream. Baptist preacher who led the American civil rights movement with nonviolent protest. Organized the March on Washington, won the Nobel Peace Prize, and was shot on a motel balcony at 39. His speeches still land today.', 'characters/mlk.webp', 38, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-mlk', 'st-mlk-i-have-a-dream');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-mandela', 'Nelson Mandela', 'From prisoner to president. Jailed for 27 years fighting apartheid. Walked out in 1990, negotiated the peaceful end of white-minority rule, and was elected South Africa''s first Black president. Chose reconciliation over revenge.', 'characters/mandela.webp', 39, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-mandela', 'st-mandela-freed');
INSERT INTO characters (id, name, description, cover_image_key, sort_order, app_id) VALUES ('ht-neil-armstrong', 'Neil Armstrong', 'One small step. Quiet Navy pilot who became the first human to walk on the moon in July 1969. Said eight words that the whole world heard. Then went home to teach engineering in Ohio like nothing happened.', 'characters/neil-armstrong.webp', 40, 'history-tea');
INSERT OR IGNORE INTO character_stories (character_id, story_id) VALUES ('ht-neil-armstrong', 'st-moon-landing');
